### Make data


::: {.cell}

```{.r .cell-code}
library(cbbplotR)
# replace NAs with empty values 
coaches <- readr::read_csv("coaching.csv") |> 
  dplyr::mutate(dplyr::across(everything(), ~as.character(.))) |>
  dplyr::mutate(dplyr::across(everything(), ~dplyr::coalesce(., "")))

# split the table 
all_coaches <- coaches |> 
  dplyr::mutate(f_team = dplyr::if_else(f_team == "", "Duke", f_team)) |> 
  cbbplotR::gt_cbb_teams(f_team, f_team) |> 
  dplyr::mutate(f_team = dplyr::if_else(f_team == "<img src='http://a.espncdn.com/i/teamlogos/ncaa/500/150.png' style='height: 25px; width: auto; vertical-align: -30%;'> Duke", 
                                        "", f_team),
                s_team = dplyr::if_else(s_team == "Manchester City", 
                                        "<img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/soccer/500/382.png' style='height: 25px; width: auto; vertical-align: -30%;'> Manchester City", 
                                        s_team),
                s_team = dplyr::if_else(s_team == "Arsenal", 
                                        "<img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/soccer/500/359.png' style='height: 25px; width: auto; vertical-align: -30%;'> Arsenal", 
                                        s_team),
                s_team = dplyr::if_else(s_team == "Manchester United", 
                                        "<img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/soccer/500/360.png' style='height: 25px; width: auto; vertical-align: -30%;'> Manchester United", 
                                        s_team),
                s_team = dplyr::if_else(s_team == "Aston Villa", 
                                        "<img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/soccer/500/362.png' style='height: 25px; width: auto; vertical-align: -30%;'> Aston Villa", 
                                        s_team),
                s_team = dplyr::if_else(s_team == "Liverpool", 
                                        "<img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/soccer/500/364.png' style='height: 25px; width: auto; vertical-align: -30%;'> Liverpool", 
                                        s_team),
                 ) |> 
  dplyr::mutate(f_coach_salary = paste0(f_coach, ", $", f_comp, " ", "million"),
                s_coach_salary = paste0(s_coach, ", $", s_comp, " ", "million"),
                f_coach_salary = dplyr::if_else(f_coach_salary == ", $ million", "", 
                                                f_coach_salary),
                s_coach_salary = dplyr::if_else(s_coach_salary == ", $ million", "", 
                                                s_coach_salary),
                money = paste0("$", money, "M"),
                money =  dplyr::if_else(money == "$M", "", 
                                       money)
                ) |>  
  dplyr::select(f_team, f_coach_salary, money, s_team, s_coach_salary) 

first_tab <- all_coaches |> 
  dplyr::slice(1:15) |> 
  dplyr::mutate(rank = dplyr::row_number()) |> 
  dplyr::relocate(rank, .before = f_team)

second_tab <- all_coaches |> 
  dplyr::slice(16:30) |> 
    dplyr::mutate(rank = dplyr::row_number() + 15) |> 
    dplyr::relocate(rank, .before = f_team)


# combine the two 

full_list <- first_tab |> 
  dplyr::bind_cols(second_tab) 
```
:::


