       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>2024 Coaching Compensation</span><span style='display: block; font-weight: bold; text-align: center; font-size: 18px;'>College Football and English Premier League</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Compares the annual compensation of college football coaches and EPL managers.</span>
     </div>
     <div>
       <img src='https://upload.wikimedia.org/wikipedia/en/thumb/f/f2/Premier_League_Logo.svg/1200px-Premier_League_Logo.svg.png' 
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)
```
