### GT Table and styles


::: {.cell}

```{.r .cell-code}
cfb_epl_tbl <- full_list |> 
  gt::gt() |> 
  gt::fmt_markdown(columns = c(f_team...2),
                   rows = c(8:15)) |> 
  gt::fmt_markdown(columns = c(s_team...5),
                   rows = c(1, 11)) |> 
  gt::fmt_markdown(columns = c(f_team...8)) |> 
  gt::fmt_markdown(columns = c(s_team...11),
                   rows = c(1, 5, 12)) |> 
  gtExtras::gt_merge_stack(
    col1 = f_team...2,
    col2 = f_coach_salary...3,
    palette = c("black", "#333333")
  ) |> 
  gtExtras::gt_merge_stack(
    col1 = s_team...5,
    col2 = s_coach_salary...6,
    palette = c("black", "#333333")
  ) |> 
  gtExtras::gt_merge_stack(
    col1 = f_team...8,
    col2 = f_coach_salary...9,
    palette = c("black", "#333333")
  ) |> 
  gtExtras::gt_merge_stack(
    col1 = s_team...11,
    col2 = s_coach_salary...12,
    palette = c("black", "#333333")
  ) |> 
  gt::cols_align(columns = c(f_team...2, s_team...5, f_team...8, s_team...11), 
                 align = "left") |> 
  gt::cols_align(columns = c(money...4, money...10), 
                 align = "center") |> 
  gtExtras::gt_add_divider(columns = c(money...4, s_team...5, rank...7,
                                       money...10, s_team...11), 
                           sides = "left", color = "black") |> 
  gt::cols_label(
    rank...1 = "",
    f_team...2 = gt::html("College<br>Football<br>Coaches"),
    f_coach_salary...3 = "",
    money...4 = gt::html("Annual<br>Compensation<br>Millions"),
    s_team...5 = gt::html("Premier<br>League<br>Managers"),
    s_coach_salary...6 = "",
    rank...7 = "",
    f_team...8 = gt::html("College<br>Football<br>Coaches"),
    f_coach_salary...9 = "",
    money...10 = gt::html("Annual<br>Compensation<br>Millions"),
    s_team...11 = gt::html("Premier<br>League<br>Managers"),
    s_coach_salary...12 = "",
  ) |> 
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(source_note = gt::html("<hr>
                                       Data from FrontOfficeSports.com | Theme from cbbplotR and logos from ESPN.com<br>
                                       Shows 23 college football coaches with an annual salary of ~$6.5 million. There are 134 FBS programs.<br>
                                       Shows four EPL managers that make ~$7 million or more. There are 20 teams in the EPL. 
                                       <hr>
                                       <b>Table by Chris (@dadgumboxscores) + Bless your chart | August 7, 2024</b>")) |> 
  cbbplotR::gt_theme_savant() |> 
  gtExtras::gt_highlight_rows(rows = c(1), fill = "#45aa15", 
                              columns = c(money...4)
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(8), fill = "#5ade1b", 
                              columns = c(money...4)
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(11), fill = "#72e73a", 
                              columns = c(money...4)
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(1), fill = "#8beb5d", 
                              columns = c(money...10)
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(5), fill = "#b0f191", 
                              columns = c(money...10)
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(10), fill = "#d6f8c5", 
                              columns = c(money...10)
  ) |> 
   gt::tab_style(
    style = gt::cell_borders(sides = "top", color = 'black', weight = gt::px(1.5), style = 'solid'),
    locations = gt::cells_body(
      rows = gt::everything()
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_column_labels(),
    style = list(
      gt::cell_text(
        align = "center"
      )
    )) |> 
  gt::tab_style(
    locations = gt::cells_body(columns = c(money...4, money...10)),
    style = list(
      gt::cell_text(
        align = "center",
        size = gt::px(18),
        style = "italic",
        stretch = "ultra-expanded"
      )
    )) |> 
    gt::tab_style(
    locations = gt::cells_body(columns = c(rank...1, rank...7)),
    style = list(
      gt::cell_text(
        align = "left",
        size = gt::px(10),
        color = "#acacac",
        stretch = "ultra-condensed"
      )
    )) |> 
  gt::tab_style(
    locations = gt::cells_row_groups(groups = gt::everything()),
    style = list(
      gt::cell_text(
        align = "center"
      ),
      gt::cell_borders(sides = c("top", "right"), color = "black", weight = gt::px(2))
    )) |> 
  gt::tab_style(
    style = list(
      gt::cell_text(color = "#333333", size = gt::px(12), weight = "bold"),
      gt::cell_borders(sides = "bottom", color = "black", weight = gt::px(2))
    ),
    locations = list(
      gt::cells_column_spanners(
        spanners = gt::everything()
      )
    )
  ) |> 
    gt::tab_options(
    heading.align = "center",
  ) -> cfb_epl_tbl

gtExtras::gtsave_extra(cfb_epl_tbl, 
                       filename = "cfb_epl_tbl.png",
                       vwidth = 850,
                       expand = 10)

cfb_epl_tbl
```

